#include<bits/stdc++.h>
using namespace std;
struct node {
	int x;
	int y;

};
struct cmp {
	bool operator()(node a, node b) {
		return a.x>b.x;
	}
};
int n, m;
bool v[5005];
priority_queue<node,vector<node>,cmp> q;
vector<node> a[5005];
int prim(int ans, int x, int jian) {
    v[x]=1;
	if (ans == m) return jian;
	for (int i = 0; i < a[x].size(); i++) {
		q.push(a[x][i]);
	}
	while (!q.empty()) {
		node now = q.top();
		q.pop();
		if (!v[now.y]) {
			return prim(ans + 1, now.y, jian + now.x);
		}

	}
	return -1;
}

int main() {
	//memset(a, 127, sizeof(a));
    ios_base::sync_with_stdio(false);
	cin>>n>>m;
	for(int i=1;i<=m;i++){
        for(int j=1;j<=m;j++){
    		int z;
    		cin>>z;
            if(z==0||z>n)  a[i].push_back({n,j});
            else a[i].push_back({z, j});
        }
	}
	cout<<prim(1,1,a[1][0].x);
	return 0;
}
